// Helper function to calculate Euclidean distance squared
float euclid_dist_2(float *pt1, float *pt2, int numdims) {
    float ans = 0.0f;
    for (int i = 0; i < numdims; i++) {
        float diff = pt1[i] - pt2[i];
        ans += diff * diff;
    }
    return ans;
}

// Helper function to find the nearest cluster center
int find_nearest_point(float *pt, int nfeatures, float *clusters, int nclusters) {
    int index = 0;
    float min_dist = FLT_MAX;

    for (int i = 0; i < nclusters; i++) {
        float dist = euclid_dist_2(pt, clusters + (i * nfeatures), nfeatures);
        if (dist < min_dist) {
            min_dist = dist;
            index = i;
        }
    }
    return index;
}

// Kernel to initialize cluster centers with the first n points and reset membership
__kernel void kmeans_init_kernel(float *feature,
                                 float *clusters,
                                 int *membership,
                                 int nfeatures,
                                 int nclusters,
                                 int npoints) {
    int i = get_global_id(0);

    if (i < nclusters) {
        // Initialize cluster i with feature point i (assuming nclusters <= npoints)
        for (int j = 0; j < nfeatures; j++) {
            clusters[i * nfeatures + j] = feature[i * nfeatures + j];
        }
    }

    if (i < npoints) {
        membership[i] = -1;
    }
}

// Kernel to assign points to nearest clusters and accumulate partial sums
// Each work group corresponds to one "thread" in the OpenMP model
__kernel void kmeans_assign_kernel(float *feature,
                                   float *clusters,
                                   int *membership,
                                   int *partial_new_centers_len,
                                   float *partial_new_centers,
                                   int nfeatures,
                                   int nclusters,
                                   int npoints,
                                   int nthreads,
                                   volatile float *delta_global) {
    int i = get_global_id(0);
    int tid = get_group_id(0); // Map group ID to thread ID

    if (i >= npoints || tid >= nthreads) return;

    float *pt = feature + (i * nfeatures);

    // Find nearest cluster
    int index = find_nearest_point(pt, nfeatures, clusters, nclusters);

    // Check for change
    float delta_val = 0.0f;
    if (membership[i] != index) {
        delta_val = 1.0f;
    }

    // Update membership
    membership[i] = index;

    // Update partial sums for this thread
    int len_idx = tid * nclusters + index;
    partial_new_centers_len[len_idx]++;

    float *partial_center = partial_new_centers + (tid * nclusters * nfeatures) + (index * nfeatures);

    for (int j = 0; j < nfeatures; j++) {
        partial_center[j] += pt[j];
    }

    // Accumulate delta globally
    if (delta_val > 0.0f) {
        atomic_add(delta_global, 1);
    }
}

// Kernel to aggregate partial sums and update cluster centers
__kernel void kmeans_update_kernel(float *clusters,
                                   float *new_centers,
                                   int *new_centers_len,
                                   int *partial_new_centers_len,
                                   float *partial_new_centers,
                                   int nfeatures,
                                   int nclusters,
                                   int nthreads) {
    int i = get_global_id(0); // Cluster index

    if (i >= nclusters) return;

    int total_count = 0;

    // Aggregate from all threads
    for (int t = 0; t < nthreads; t++) {
        int len_idx = t * nclusters + i;
        int count = partial_new_centers_len[len_idx];
        total_count += count;

        float *partial_center = partial_new_centers + (t * nclusters * nfeatures) + (i * nfeatures);
        float *new_center = new_centers + (i * nfeatures);

        for (int j = 0; j < nfeatures; j++) {
            new_center[j] += partial_center[j];
            // Reset partials for next iteration
            partial_center[j] = 0.0f;
        }

        // Reset partial count
        partial_new_centers_len[len_idx] = 0;
    }

    // Update center if there are points
    if (total_count > 0) {
        float *new_center = new_centers + (i * nfeatures);
        float *cluster = clusters + (i * nfeatures);
        float inv_count = 1.0f / (float)total_count;

        for (int j = 0; j < nfeatures; j++) {
            cluster[j] = new_center[j] * inv_count;
            new_center[j] = 0.0f; // Reset for next
        }
    }

